import React from "react";
import styles from "./product-card.module.css";
import { Link, useNavigate } from "react-router-dom";

interface CardProps {
  id: number;
  imgSrc: string;
  name: string;
  price: number;
}

const ProductCard: React.FC<CardProps> = ({ id, imgSrc, name, price }) => {
  const navigate = useHistory();

  const handleCardClick = () => {
    // Redirect to the product details page with the product ID in the URL
    history.push(`/product/${id}`);
  };

  return (
    <div className={styles.wrapper_card} onClick={handleCardClick}>
      <div className={styles.card_top}>
        <img src={imgSrc} className={styles.card_image} alt="product" />
      </div>
      <div className={styles.card_body}>
        <Link to={`/product/${id}`}>
          <h4 className={styles.card_title}>{name}</h4>
        </Link>
      </div>
      <div className={styles.card_bottom}>
        <span className={styles.card_price}>${price}</span>
      </div>
    </div>
  );
};

export default ProductCard;


